class Person:
    def __init__(self, förnamn, efternamn, födelseår):
      self.förnamn = förnamn
      self.efternamn = efternamn
      self.födelseår = födelseår

    def __str__(self):
      return self.förnamn + ": " + str(2018 - self.födelseår)

    def skrivIntro(self):
      print("Hej jag heter " + self.förnamn + " " + self.efternamn + " och jag är " + str(self.födelseår) + " år gammal")

kim = Person("Kim","Efternamnsson", 1995)
print(kim)
